```class Solution {
public:
    int countSubstrings(string s) {
        int n = s.size(), res = 0;
        for (int i = 0; i < n; ++i) {
            res += expandAroundCenter(s, i, i); // odd length palindrome
            res += expandAroundCenter(s, i, i + 1); // even length palindrome
        }
        return res;
    }
private:
    int expandAroundCenter(string s, int left, int right) {
        int res = 0;
        while (left >= 0 && right < s.size() && s[left] == s[right]) {
            res++;
            left--;
            right++;
        }
        return res;
    }
};
